/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 1000000007;

    // --- Modular Arithmetic Functions ---

    /**
     * Modular exponentiation: (base^exp) % mod
     */
    const power = (base, exp) => {
        let res = 1n;
        base = BigInt(base) % BigInt(MOD);
        exp = BigInt(exp);
        const m = BigInt(MOD);

        while (exp > 0n) {
            if (exp % 2n === 1n) {
                res = (res * base) % m;
            }
            base = (base * base) % m;
            exp /= 2n;
        }
        return Number(res);
    };

    /**
     * Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
     */
    const modInverse = (n) => {
        return power(n, MOD - 2);
    };

    // --- Precalculation of Factorials ---

    // We need factorials up to N (max 10^5)
    const MAX_N = n;
    const fact = new Array(MAX_N + 1);
    fact[0] = 1;
    for (let i = 1; i <= MAX_N; i++) {
        fact[i] = (BigInt(fact[i - 1]) * BigInt(i)) % BigInt(MOD);
    }

    /**
     * Combinations: nCk % MOD
     */
    const nCr = (n_val, r_val) => {
        if (r_val < 0 || r_val > n_val) {
            return 0;
        }
        if (r_val === 0 || r_val === n_val) {
            return 1;
        }
        if (r_val > n_val / 2) {
            r_val = n_val - r_val;
        }

        // nCr = n! / (r! * (n-r)!)
        const numerator = BigInt(fact[n_val]);
        const denominator = (BigInt(fact[r_val]) * BigInt(fact[n_val - r_val])) % BigInt(MOD);

        const inv_denominator = BigInt(modInverse(Number(denominator)));

        return Number((numerator * inv_denominator) % BigInt(MOD));
    };

    // --- Problem Logic ---

    // L: number of people to the left of pos (indices 0 to pos-1)
    const L = pos;
    // R: number of people to the right of pos (indices pos+1 to N-1)
    const R = n - 1 - pos;

    let totalWays = 0n;

    // We need k_L + k_R = k
    // k_L must satisfy: 0 <= k_L <= L
    // k_R = k - k_L must satisfy: 0 <= k - k_L <= R
    // => k - R <= k_L <= k

    // Determine the range for k_L
    const start_kL = Math.max(0, k - R);
    const end_kL = Math.min(L, k);

    for (let k_L = start_kL; k_L <= end_kL; k_L++) {
        const k_R = k - k_L;

        // Ways to choose k_L visible people from L people: C(L, k_L)
        const waysL = BigInt(nCr(L, k_L));

        // Ways to choose k_R visible people from R people: C(R, k_R)
        const waysR = BigInt(nCr(R, k_R));

        // Contribution for this k_L: C(L, k_L) * C(R, k_R)
        const contribution = (waysL * waysR) % BigInt(MOD);

        totalWays = (totalWays + contribution) % BigInt(MOD);
    }

    // Person at pos has 2 independent choices ('L' or 'R') which multiply the count.
    const finalAnswer = (totalWays * 2n) % BigInt(MOD);

    return Number(finalAnswer);
}

