    ll res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

// Modular inverse using Fermat's Little Theorem: a^(MOD-2) % MOD
ll modInverse(ll n) {
    return power(n, MOD - 2);
}

// Precompute factorials up to max_n
void precompute_factorials(int max_n) {
    fact.resize(max_n + 1);
    fact[0] = 1;
    for (int i = 1; i <= max_n; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }
}

// Combinations: nCk % MOD
ll nCr(int n_val, int r_val) {
    if (r_val < 0 || r_val > n_val) {
        return 0;
    }
    // nCr = n! / (r! * (n-r)!)
    ll numerator = fact[n_val];
    ll denominator = (fact[r_val] * fact[n_val - r_val]) % MOD;

    ll inv_denominator = modInverse(denominator);

    return (numerator * inv_denominator) % MOD;
}


long long solve(long long n_ll, long long pos_ll, long long k_ll) {
    // Since N <= 10^5, we can safely cast to int for array indexing, 
    // but we must use long long for inputs and results.
    int n = (int)n_ll;
    int pos = (int)pos_ll;
    int k = (int)k_ll;

    // Precompute factorials up to N
    precompute_factorials(n);

    // L: number of people to the left of pos (0 to pos-1)
    ll L = pos;
    // R: number of people to the right of pos (pos+1 to N-1)
    ll R = n - 1 - pos;

    ll totalWays = 0;

    // We iterate over k_L, the number of visible people from the left.
    // We require k_L + k_R = k.

    // k_L constraints:
    // 1. 0 <= k_L <= L
    // 2. 0 <= k_R <= R  => 0 <= k - k_L <= R
    //    k - k_L >= 0  => k_L <= k
    //    k - k_L <= R  => k_L >= k - R

    // Determine the range for k_L
    ll start_kL = max(0LL, k - R);
    ll end_kL = min(L, k);

    for (ll k_L = start_kL; k_L <= end_kL; k_L++) {
        ll k_R = k - k_L;

        // Ways to choose k_L visible people from L people: C(L, k_L)
        ll waysL = nCr((int)L, (int)k_L);

        // Ways to choose k_R visible people from R people: C(R, k_R)
        ll waysR = nCr((int)R, (int)k_R);

        // Contribution for this k_L: C(L, k_L) * C(R, k_R)
        ll contribution = (waysL * waysR) % MOD;

        totalWays = (totalWays + contribution) % MOD;
