using namespace std;

typedef long long ll;
const int MOD = 1e9 + 7;

// Helper functions for modular arithmetic
ll power(ll base, ll exp) {
    ll res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

ll modInverse(ll n) {
    return power(n, MOD - 2);
}

// Global or static storage for factorials, since N <= 10^5
vector<ll> fact;

void precompute_factorials(int max_n) {
    fact.resize(max_n + 1);
    fact[0] = 1;
    for (int i = 1; i <= max_n; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }
}

ll nCr(int n_val, int r_val) {
    if (r_val < 0 || r_val > n_val) {
        return 0;
    }
    if (r_val == 0 || r_val == n_val) {
        return 1;
    }
    // nCr = n! / (r! * (n-r)!)
    ll numerator = fact[n_val];
    ll denominator = (fact[r_val] * fact[n_val - r_val]) % MOD;

    ll inv_denominator = modInverse(denominator);

    return (numerator * inv_denominator) % MOD;
}

long long solve(long long n, long long pos, long long k) {
    // Since N <= 10^5, we precalculate factorials up to N.
    // We must ensure this is done only once, but for contest setup,
    // calling it here assuming constraints hold.
    // We cast inputs to int safely as N <= 10^5.
    int N_int = (int)n;
    precompute_factorials(N_int);

    // L: number of people to the left of pos (indices 0 to pos-1)
    ll L = pos;
    // R: number of people to the right of pos (indices pos+1 to N-1)
    ll R = n - 1 - pos;
    ll K_ll = k; // Use ll for K consistency

    ll totalWaysSum = 0;

    // We need k_L + k_R = K
    // k_L range:
    // 1. 0 <= k_L <= L
    // 2. 0 <= K - k_L <= R  => K - R <= k_L <= K

    // Determine the range for k_L (must be cast to int since L, R <= 10^5)
    int start_kL = max(0LL, K_ll - R);
    int end_kL = min(L, K_ll);

    for (int k_L = start_kL; k_L <= end_kL; k_L++) {
        ll k_R = K_ll - k_L;

        // Ways to choose k_L visible people from L people: C(L, k_L)
        ll waysL = nCr((int)L, k_L);

        // Ways to choose k_R visible people from R people: C(R, k_R)
        ll waysR = nCr((int)R, (int)k_R);

        // Contribution for this k_L: C(L, k_L) * C(R, k_R)
        ll contribution = (waysL * waysR) % MOD;

        totalWaysSum = (totalWaysSum + contribution) % MOD;
    }

    // The person at pos has 2 independent choices ('L' or 'R'), which multiply the count.
    ll finalAnswer = (totalWaysSum * 2) % MOD;

    return finalAnswer;
}

